// game-of-life.spec.ts
import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array for a single live cell (underpopulation)");
  it.todo("should return empty array for two adjacent cells, each with one neighbor (underpopulation)");
  it.todo("should keep alive a cell with three live neighbors (survival)");
  it.todo("should kill a live cell with more than three live neighbors (overpopulation)");
  it.todo("should bring to life a dead cell with exactly three live neighbors (reproduction)");
  it.todo("should keep a block still life unchanged");
  it.todo("should rotate a vertical blinker into a horizontal blinker including negative coordinates");
});
